libraries/transport/sse/port.ts
type SseClient = {
connect(
url, events, onEvent, onStateChange?
): SseConnection
}
type SseState = "connecting" | "open" | "closed" | "error"
type SseEvents = イベント名 と Zod スキーマのマップ

libraries/transport/ws/port.ts
type WsClient = {
connect(
url, events, onEvent, onStateChange?
): WsConnection
}
type WsConnection = {
send(name, data)
close()
}
type WsState は SseState と同一

